INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('92a082b4-89b7-491c-a783-39088d0397e1', $q$Cloud VoIP calling$q$, $q$Business phone service with unlimited domestic calling, auto attendants, call queues, and call forwarding, all managed from a web admin console.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('92a082b4-89b7-491c-a783-39088d0397e1', $q$Team messaging$q$, $q$Built-in chat with channels, direct messages, file sharing, and task tracking alongside calling and meetings in the same app.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('92a082b4-89b7-491c-a783-39088d0397e1', $q$Video meetings$q$, $q$Integrated video conferencing with screen sharing and participant capacity that scales by plan tier.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('92a082b4-89b7-491c-a783-39088d0397e1', $q$Voicemail-to-text$q$, $q$Automatic transcription of voicemails so users can read messages instead of listening to every recording.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('92a082b4-89b7-491c-a783-39088d0397e1', $q$Call recording and monitoring$q$, $q$Automatic call recording plus supervisor tools like call whisper and barge on higher-tier plans, useful for coaching sales and support teams.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('92a082b4-89b7-491c-a783-39088d0397e1', $q$CRM and helpdesk integrations$q$, $q$Native connections to tools such as Salesforce, HubSpot, and Zendesk for logging calls and syncing customer data.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('92a082b4-89b7-491c-a783-39088d0397e1', $q$AI-powered summaries$q$, $q$AI-generated recaps of calls and meetings intended to reduce manual note-taking for sales and support conversations.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('92a082b4-89b7-491c-a783-39088d0397e1', $q$AI receptionist add-on$q$, $q$An optional automated attendant that can answer, screen, and route incoming calls without a live employee.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('92a082b4-89b7-491c-a783-39088d0397e1', $q$Developer APIs$q$, $q$A documented API and SDK set for embedding RingCentral calling, SMS, and messaging into custom internal tools or products.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('92a082b4-89b7-491c-a783-39088d0397e1', $q$Multi-location administration$q$, $q$Centralized management of numbers, extensions, and routing rules across offices, branches, or remote teams from one console.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('92a082b4-89b7-491c-a783-39088d0397e1', $q$Combines phone, messaging, and video meetings in one subscription, reducing the need for separate tools$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('92a082b4-89b7-491c-a783-39088d0397e1', $q$Scales from small offices to large, multi-location organizations on the same platform$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('92a082b4-89b7-491c-a783-39088d0397e1', $q$Long operating history in business communications with a broad partner and integration ecosystem$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('92a082b4-89b7-491c-a783-39088d0397e1', $q$Tiered plans let teams pay for advanced features like call recording only where they are needed$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('92a082b4-89b7-491c-a783-39088d0397e1', $q$Developer APIs support custom integrations for technical teams$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('92a082b4-89b7-491c-a783-39088d0397e1', $q$Entry-level plan limits SMS volume and lacks automatic call recording, pushing some teams to upgrade$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('92a082b4-89b7-491c-a783-39088d0397e1', $q$Add-ons for AI receptionist, conversational intelligence, and other features carry separate costs$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('92a082b4-89b7-491c-a783-39088d0397e1', $q$Per-user monthly pricing across multiple tiers can make total cost harder to predict than flat-rate alternatives$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('92a082b4-89b7-491c-a783-39088d0397e1', $q$Advanced contact-center capabilities require a separate product rather than being included in RingEX$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('92a082b4-89b7-491c-a783-39088d0397e1', $q$Admin console has enough configuration options that setup can take longer than a simpler, lightweight VoIP app$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('92a082b4-89b7-491c-a783-39088d0397e1', $q$Does RingCentral offer a free plan?$q$, $q$RingCentral does not offer an ongoing free plan; it offers a limited-time free trial that gives access to core calling, messaging, and meeting features before requiring a paid subscription.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('92a082b4-89b7-491c-a783-39088d0397e1', $q$What is the starting price for RingCentral?$q$, $q$Pricing starts at the Core plan, billed per user per month, with lower rates available when billing annually rather than monthly. Exact pricing can vary by region, number of users, and promotions, so confirming current rates on RingCentral's pricing page is recommended.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('92a082b4-89b7-491c-a783-39088d0397e1', $q$Can I keep my existing business phone number with RingCentral?$q$, $q$Yes, RingCentral supports porting existing phone numbers from other carriers as part of account setup, which is a common step for businesses switching from a legacy phone system.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('92a082b4-89b7-491c-a783-39088d0397e1', $q$Is RingCentral suitable for a small business with just a few employees?$q$, $q$It can work for small teams that want unified calling, messaging, and meetings, though very small teams with light calling needs may find the per-user pricing and add-on fees more than a simpler VoIP tool would cost.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('92a082b4-89b7-491c-a783-39088d0397e1', $q$Does RingCentral integrate with CRM tools like Salesforce or HubSpot?$q$, $q$Yes, RingCentral offers native integrations with popular CRM and helpdesk platforms including Salesforce, HubSpot, and Zendesk, primarily available on its higher-tier plans.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('92a082b4-89b7-491c-a783-39088d0397e1', $q$Replacing a legacy office phone system$q$, $q$A company retires an on-premises PBX and desk-phone infrastructure in favor of a cloud-based system managed entirely from a web console.$q$, $q$Small and mid-sized businesses modernizing office communications$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('92a082b4-89b7-491c-a783-39088d0397e1', $q$Unifying multi-location call routing$q$, $q$A multi-branch business or franchise standardizes phone numbers, auto attendants, and call routing across all locations from a single admin account.$q$, $q$Franchises and multi-office organizations$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('92a082b4-89b7-491c-a783-39088d0397e1', $q$Supporting a remote or hybrid sales team$q$, $q$A distributed sales team uses one app for calling leads, messaging teammates, and joining video meetings, with call recording and CRM logging for coaching.$q$, $q$Remote and hybrid sales and support teams$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('92a082b4-89b7-491c-a783-39088d0397e1', $q$Embedding communications into internal tools$q$, $q$A technical team uses RingCentral's developer APIs to add click-to-call, SMS, or messaging capabilities directly into an internal application or workflow.$q$, $q$Developers and IT teams building custom integrations$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('92a082b4-89b7-491c-a783-39088d0397e1', $q$Core$q$, $q$$20/user/month (annual) or $30/user/month (monthly)$q$, $q$monthly or annual$q$, $q$["Unlimited domestic calling","Auto attendant and call queues","Voicemail-to-text","Team messaging","Video meetings for up to 100 participants","Limited SMS per user per month"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('92a082b4-89b7-491c-a783-39088d0397e1', $q$Advanced$q$, $q$$25/user/month (annual) or $35/user/month (monthly)$q$, $q$monthly or annual$q$, $q$["Everything in Core","Automatic call recording","Advanced call monitoring (whisper and barge)","CRM integrations with Salesforce, HubSpot, and Zendesk","Higher SMS allowance"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('92a082b4-89b7-491c-a783-39088d0397e1', $q$Ultra$q$, $q$$35/user/month (annual) or $45/user/month (monthly)$q$, $q$monthly or annual$q$, $q$["Everything in Advanced","Unlimited storage for files and recordings","Toll-free minutes included","Priority support options"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('92a082b4-89b7-491c-a783-39088d0397e1', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$RingCentral is a cloud communications platform that replaces traditional office phone hardware with a software-based system for calling, SMS, team messaging, and video meetings. Founded in 1999 and headquartered in Belmont, California, the company built its business around unified communications as a service, letting organizations run their entire phone system from a browser, desktop app, or mobile device instead of a PBX closet.$q$, $q$The core product, marketed as RingEX, bundles a business VoIP phone system with auto attendants, call queues, voicemail transcription, and internal team chat in a single subscription. RingCentral also sells adjacent products for video meetings and contact center operations, so a company can start with just phone service and expand into a fuller communications stack as needs grow.$q$, $q$Because it targets everything from five-person offices to large distributed enterprises, RingCentral's plans and add-ons are heavily tiered. That flexibility is a selling point for companies that want one vendor for calling, messaging, and meetings, but it also means the right plan and the total monthly cost depend a lot on headcount, call volume, and which integrations or AI features a team actually needs. As one of the longer-established names in cloud business communications, RingCentral has also had time to build out partnerships with hardware makers, CRM vendors, and telecom carriers across multiple countries, which shows up as broader compliance certifications and international number availability than many newer VoIP entrants offer.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('92a082b4-89b7-491c-a783-39088d0397e1', $q$who-ringcentral-is-for$q$, $q$Who RingCentral Is For$q$, 2, ARRAY[$q$RingCentral fits small and mid-sized businesses that want to retire a legacy desk-phone system without hiring telecom staff to manage it. A single admin console lets a small office manager set up extensions, auto attendants, and call routing rules without needing a background in PBX configuration.$q$, $q$It also serves multi-location businesses and franchises that need consistent phone numbers, call routing, and messaging across branches, since the whole system is centrally administered even when employees are spread across cities or time zones. Sales and support teams that already rely on Salesforce, HubSpot, or Zendesk are a strong fit too, given RingCentral's built-in CRM integrations and call-logging features on its higher tiers.$q$, $q$Remote and hybrid teams that want calling, chat, and video meetings from one login rather than juggling separate tools for each often choose RingCentral for that consolidation. IT teams evaluating a vendor with a long operating history and enterprise-grade compliance and security options also tend to shortlist it alongside other established unified-communications providers. Growing companies that expect to add locations, departments, or headcount over the next few years also benefit from RingCentral's tiered structure, since new users and features can be added without migrating to an entirely different system as the business scales.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('92a082b4-89b7-491c-a783-39088d0397e1', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Solo founders or very small teams with minimal calling needs may find RingCentral more infrastructure than they require, since per-user monthly pricing and add-on fees for features like AI receptionist or advanced call recording can add up quickly compared to a lightweight VoIP app.$q$, $q$Businesses that need heavy SMS marketing volume out of the box should look closely at the plan limits first, since entry-level tiers cap monthly text messages per user and require an add-on or upgrade to remove that ceiling. Teams whose core need is a full-featured contact center with deep workforce management may also outgrow RingEX and need RingCentral's separate contact center product or a dedicated contact-center vendor instead.$q$, $q$Companies that prioritize a single, simple flat price over configurability may find the multi-tier structure and optional add-ons harder to budget for than a flat-rate competitor. Organizations without any IT support may also want a vendor with more hands-on, done-for-you onboarding rather than a self-serve admin portal.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('92a082b4-89b7-491c-a783-39088d0397e1', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$RingCentral's foundation is cloud-based VoIP calling with unlimited domestic calling on most plans, along with auto attendants, call queues, call forwarding, and voicemail-to-text transcription. Team messaging is built in, so employees can chat, share files, and manage tasks in the same app used for calls.$q$, $q$Video meetings are included across plans, supporting screen sharing and a meeting-participant capacity that scales with the plan tier. Higher tiers add automatic call recording, call monitoring features like whisper and barge for coaching, and native integrations with CRM and helpdesk tools such as Salesforce, HubSpot, and Zendesk.$q$, $q$RingCentral has also layered AI features into the platform, including AI-generated call and meeting summaries, conversational intelligence for analyzing customer calls, and an AI receptionist add-on that can answer and route calls automatically. An open developer platform and APIs let technical teams build custom integrations or embed RingCentral's calling and messaging capabilities into their own applications.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('92a082b4-89b7-491c-a783-39088d0397e1', $q$the-ringcentral-experience$q$, $q$The RingCentral Experience$q$, 2, ARRAY[$q$Day to day, most users interact with RingCentral through its desktop and mobile apps, which combine a phone dialer, message threads, and a meetings launcher in one interface. Admins manage numbers, extensions, and permissions from a separate web-based admin console that does not require any on-site hardware beyond desk phones or headsets employees already have.$q$, $q$Setup typically involves porting existing phone numbers, configuring auto attendants and call queues, and assigning users to a plan tier based on which features they need, such as call recording or CRM integration. Because features and limits vary by tier, teams often spend some time during onboarding mapping departments to the right plan rather than giving everyone the top tier by default.$q$, $q$Ongoing use tends to center on call handling and internal chat, with meetings and AI summaries used more selectively depending on the team. Support is available through in-app resources, a help center, and account-tier-based service levels, and the free trial gives new customers a way to test core calling, messaging, and meeting features before committing to an annual contract.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('92a082b4-89b7-491c-a783-39088d0397e1', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('92a082b4-89b7-491c-a783-39088d0397e1', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('92a082b4-89b7-491c-a783-39088d0397e1', '5e4d4807-cae2-410c-9e7a-df0798a917cb') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('92a082b4-89b7-491c-a783-39088d0397e1', '7336153f-a26b-491c-b927-faf4f5a8d103') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('88db22aa-79b8-45ed-b2f4-437c05395830', $q$AI meeting transcripts and recaps$q$, $q$Automatic transcription, notes, and action-item summaries are generated after eligible meetings so attendees can review decisions without manual note-taking.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('88db22aa-79b8-45ed-b2f4-437c05395830', $q$Live translation$q$, $q$Paid plans include live translation across a wide range of languages, helping distributed and international teams follow conversations in real time.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('88db22aa-79b8-45ed-b2f4-437c05395830', $q$Screen sharing and whiteboard$q$, $q$Presenters can share their screen and collaborate on an interactive whiteboard with annotation tools during any meeting.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('88db22aa-79b8-45ed-b2f4-437c05395830', $q$Breakout rooms$q$, $q$Hosts can split larger meetings into smaller breakout sessions for focused discussion before bringing everyone back together.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('88db22aa-79b8-45ed-b2f4-437c05395830', $q$Virtual backgrounds$q$, $q$Participants can apply virtual or blurred backgrounds to keep meetings professional regardless of their physical surroundings.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('88db22aa-79b8-45ed-b2f4-437c05395830', $q$Meeting recording$q$, $q$Sessions can be recorded and shared afterward via a link, giving teams a reference for anyone who missed the live meeting.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('88db22aa-79b8-45ed-b2f4-437c05395830', $q$Calendar integrations$q$, $q$Native integrations with Google Calendar and Outlook let users schedule and launch RingCentral Video meetings from the calendar apps they already use.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('88db22aa-79b8-45ed-b2f4-437c05395830', $q$Webinars and town halls$q$, $q$Beyond standard meetings, the platform supports larger broadcast-style webinars and company town halls for one-to-many communication.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('88db22aa-79b8-45ed-b2f4-437c05395830', $q$Browser-based join$q$, $q$Guests can join meetings directly from a supported web browser with no software download required.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('88db22aa-79b8-45ed-b2f4-437c05395830', $q$Meeting analytics$q$, $q$Built-in analytics give administrators visibility into meeting quality and usage trends across the organization.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('88db22aa-79b8-45ed-b2f4-437c05395830', $q$Free Video Pro tier supports up to 100 participants at no cost$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('88db22aa-79b8-45ed-b2f4-437c05395830', $q$AI-generated transcripts, notes, and recaps reduce manual meeting follow-up$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('88db22aa-79b8-45ed-b2f4-437c05395830', $q$Bundles naturally with RingCentral's broader phone and messaging platform for existing customers$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('88db22aa-79b8-45ed-b2f4-437c05395830', $q$Cross-platform coverage with browser-based join plus Windows, Mac, iOS, and Android apps$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('88db22aa-79b8-45ed-b2f4-437c05395830', $q$Supports webinars and town halls in addition to standard team meetings$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('88db22aa-79b8-45ed-b2f4-437c05395830', $q$Free plan meetings are capped at 50 minutes$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('88db22aa-79b8-45ed-b2f4-437c05395830', $q$The most useful AI features are limited to paid or RingEX-bundled plans$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('88db22aa-79b8-45ed-b2f4-437c05395830', $q$Pricing and packaging can be confusing to evaluate outside the context of a full RingEX subscription$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('88db22aa-79b8-45ed-b2f4-437c05395830', $q$Less compelling as a pure standalone video tool compared with dedicated conferencing specialists$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('88db22aa-79b8-45ed-b2f4-437c05395830', $q$Scaling beyond standard participant limits for large events typically requires a direct sales conversation$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('88db22aa-79b8-45ed-b2f4-437c05395830', $q$Is RingCentral Video free to use?$q$, $q$Yes. The Video Pro tier is free and supports meetings with up to 100 participants, though sessions are limited to 50 minutes each.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('88db22aa-79b8-45ed-b2f4-437c05395830', $q$How is RingCentral Video different from RingEX?$q$, $q$RingEX is RingCentral's broader unified communications platform, covering phone, messaging, and video. RingCentral Video is the video meetings component, which is included when you subscribe to RingEX or purchased on its own paid tier.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('88db22aa-79b8-45ed-b2f4-437c05395830', $q$Does RingCentral Video offer live translation?$q$, $q$Yes, paid plans include live translation across a wide range of languages, which is aimed at distributed and international teams.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('88db22aa-79b8-45ed-b2f4-437c05395830', $q$Do meeting guests need to create an account or download software to join?$q$, $q$No. Guests can join a RingCentral Video meeting directly from a supported web browser without installing anything, though desktop and mobile apps are also available.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('88db22aa-79b8-45ed-b2f4-437c05395830', $q$What is the maximum number of meeting participants?$q$, $q$The free Video Pro plan supports up to 100 participants, while paid and RingEX-bundled plans raise that ceiling to up to 200 participants.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('88db22aa-79b8-45ed-b2f4-437c05395830', $q$Daily team standups$q$, $q$Distributed teams use the free or paid tier for recurring check-ins, relying on screen sharing and recording for anyone who cannot attend live.$q$, $q$Remote and hybrid team leads$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('88db22aa-79b8-45ed-b2f4-437c05395830', $q$Client and sales calls$q$, $q$Sales and consulting teams host client-facing video calls and lean on AI transcripts and recaps to capture commitments and follow-up items.$q$, $q$Sales and client services teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('88db22aa-79b8-45ed-b2f4-437c05395830', $q$Company town halls and webinars$q$, $q$Internal communications teams broadcast all-hands meetings and external webinars using the platform's larger-capacity meeting and analytics tools.$q$, $q$Internal communications and marketing teams$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('88db22aa-79b8-45ed-b2f4-437c05395830', $q$Consolidating unified communications$q$, $q$IT departments already running RingEX for phone service extend usage to RingCentral Video to reduce the number of separate communication vendors.$q$, $q$IT and communications administrators$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('88db22aa-79b8-45ed-b2f4-437c05395830', $q$Video Pro$q$, $q$$0$q$, $q$Free forever$q$, $q$["Up to 100 participants","50-minute meeting limit","Screen sharing and whiteboard","Basic recording","Limited AI capabilities"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('88db22aa-79b8-45ed-b2f4-437c05395830', $q$Video Pro+$q$, $q$$10/user/month$q$, $q$Billed annually$q$, $q$["Unlimited 24-hour meetings","Up to 200 participants","Full AI transcripts, notes, and recaps","Live translation","Dynamic end-to-end encryption","Increased cloud recording storage"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('88db22aa-79b8-45ed-b2f4-437c05395830', $q$RingEX (bundled)$q$, $q$Contact for pricing$q$, $q$Custom$q$, $q$["RingCentral Video included alongside cloud phone and messaging","Unified admin console and analytics","Full AI meeting features included","Enterprise-grade security and compliance options"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('88db22aa-79b8-45ed-b2f4-437c05395830', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$RingCentral Video is the video meetings product built by RingCentral, Inc., a cloud communications company founded in 1999 and headquartered in Belmont, California. Rather than existing as a standalone startup tool, RingCentral Video is one pillar of a much larger unified communications business that also spans cloud phone systems, team messaging, and contact center software sold under the RingEX and RingCentral MVP umbrellas, giving the product a level of engineering and support resources smaller independent video vendors rarely have. Because it is developed alongside the company's phone and messaging products, it shares infrastructure, security practices, and administrative tooling with the rest of the suite, which can be an advantage for organizations that value a single vendor relationship.$q$, $q$The product's headline draw is a genuinely usable free tier: RingCentral Video Pro lets anyone host meetings with up to 100 participants at no cost, with a 50-minute limit per session. Customers on paid meetings plans or full RingEX subscriptions remove that time cap, gaining unlimited 24-hour meetings for up to 200 participants along with AI-generated transcripts, notes, and recaps built into the price rather than sold as a separate add-on.$q$, $q$Meetings run in a browser with no download required, and dedicated desktop and mobile apps are also available for teams that want a persistent client with notifications and quick-launch shortcuts. Positioned against Zoom, Microsoft Teams, and Google Meet, RingCentral Video's differentiator is less about novel video technology and more about how tightly it folds into a broader phone-and-messaging platform many mid-market and enterprise buyers already run day to day.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('88db22aa-79b8-45ed-b2f4-437c05395830', $q$who-ringcentral-video-is-for$q$, $q$Who RingCentral Video Is For$q$, 2, ARRAY[$q$Organizations already running RingEX or RingCentral MVP for business phone service are the clearest fit, since video is bundled into those subscriptions rather than billed as a separate line item. For IT teams trying to consolidate vendors, using the video tool that ships with the phone system reduces the number of logins, invoices, and admin consoles staff have to manage across the organization.$q$, $q$Small teams and freelancers who just need a dependable, no-frills meeting tool can also get real value from the free Video Pro tier, since 100 participants and 50 minutes covers the vast majority of internal check-ins, client calls, and interviews without ever entering a credit card or committing to a contract.$q$, $q$Mid-market and enterprise communications teams running larger internal broadcasts, town halls, or customer-facing webinars are another strong match, particularly once they need the AI-generated recaps, live translation, and higher participant ceilings that come with paid plans, along with the analytics needed to prove those sessions are effective.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('88db22aa-79b8-45ed-b2f4-437c05395830', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Teams that need a lightweight, single-purpose video app and nothing else may find RingCentral Video's positioning inside a much larger communications suite unnecessarily heavy. Buyers who only want video, with no phone or contact center component, are often better served evaluating a dedicated conferencing product on its own merits rather than adopting a bundled platform.$q$, $q$Highly price-sensitive users who are not already RingCentral customers may not see enough advantage over free-first competitors like Google Meet, since RingCentral Video's most compelling AI capabilities are reserved for paid or RingEX-bundled plans rather than the free Video Pro tier that most casual users would start with.$q$, $q$Companies planning very large-scale public webinars or events beyond the standard participant ceilings should confirm current capacity and any add-on requirements directly with RingCentral sales, since scaling past the built-in limits typically involves additional licensing conversations rather than a simple self-serve upgrade inside the account settings.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('88db22aa-79b8-45ed-b2f4-437c05395830', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At its core, RingCentral Video covers the expected video conferencing basics: screen sharing, an interactive whiteboard with annotations, breakout rooms, virtual backgrounds, and dynamic end-to-end encryption for sensitive sessions. Meetings can be joined directly from a browser or through the desktop and mobile apps, with an audio and video preview before entering the room.$q$, $q$On top of those fundamentals, RingCentral layers AI-driven capabilities: automatic transcription, meeting notes, action-item summaries, and live translation across a wide set of languages for paying customers. Smart scheduling features check attendee availability and can reach guests through their preferred channel when setting up invites, cutting down on scheduling back-and-forth.$q$, $q$For larger-scale communication needs, the product supports webinars and town halls alongside standard meetings, plus built-in analytics that surface meeting quality metrics for administrators. Native calendar integrations with Google Calendar and Outlook keep scheduling inside the tools teams already use day to day, rather than forcing a separate booking workflow, and recordings can be organized and revisited later from cloud storage tied to the account.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('88db22aa-79b8-45ed-b2f4-437c05395830', $q$the-ringcentral-video-experience$q$, $q$The RingCentral Video Experience$q$, 2, ARRAY[$q$Joining a RingCentral Video meeting is designed to be frictionless: guests can click a link and enter through a supported web browser without installing anything, while regular users on Windows, Mac, iOS, or Android can rely on native apps for a more integrated experience alongside RingCentral's phone and messaging tools in one client.$q$, $q$Once inside a meeting, the interface favors a familiar layout, with recording, screen sharing, and the whiteboard readily accessible, and AI notetaking running quietly in the background for eligible plans so hosts can focus on the conversation instead of manual note-taking or chasing down follow-up items afterward.$q$, $q$After a call ends, participants on paid or RingEX plans receive AI-generated recaps and searchable transcripts, and recordings can be shared out with a link so anyone who missed the session can catch up quickly. For administrators, the surrounding RingCentral admin console ties video usage and quality analytics into the same dashboard used to manage phone lines and team messaging, simplifying day-to-day oversight and reducing the number of separate systems IT has to monitor.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('88db22aa-79b8-45ed-b2f4-437c05395830', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
