INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7f58ae22-1c44-4f9a-9b61-75861272aaaa', '7336153f-a26b-491c-b927-faf4f5a8d103') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('56d2b2f0-b7a4-448f-acba-955eb269b59c', $q$Matter and Case Management$q$, $q$Centralizes documents, deadlines, contacts, and communication for each matter so attorneys can see the full history of a case in one place.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('56d2b2f0-b7a4-448f-acba-955eb269b59c', $q$Time and Expense Tracking$q$, $q$Lets timekeepers log billable and non-billable hours and expenses from a browser or mobile app, feeding directly into invoices.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('56d2b2f0-b7a4-448f-acba-955eb269b59c', $q$Legal Billing and Invoicing$q$, $q$Supports hourly and flat-fee billing with customizable invoice templates and online payment collection through Rocket Matter Pay.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('56d2b2f0-b7a4-448f-acba-955eb269b59c', $q$Trust Accounting$q$, $q$Manages client trust funds with matter-based trust accounts and controls designed to support IOLTA compliance requirements.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('56d2b2f0-b7a4-448f-acba-955eb269b59c', $q$Legal CRM$q$, $q$Tracks leads and referral sources and supports business development workflows, with an add-on tier that includes marketing automation.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('56d2b2f0-b7a4-448f-acba-955eb269b59c', $q$Calendaring and Task Management$q$, $q$Provides shared calendars and task assignment so deadlines and responsibilities across a matter are visible to the whole team.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('56d2b2f0-b7a4-448f-acba-955eb269b59c', $q$Document Automation and eSignatures$q$, $q$Generates documents from templates and supports electronic signature collection directly within a matter.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('56d2b2f0-b7a4-448f-acba-955eb269b59c', $q$Reporting and Dashboards$q$, $q$Offers customizable dashboards and saved views so different roles, from associates to billing administrators, can monitor the metrics relevant to them.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('56d2b2f0-b7a4-448f-acba-955eb269b59c', $q$QuickBooks Integration$q$, $q$Synchronizes billing and accounting data with QuickBooks to reduce duplicate entry between legal billing and the general ledger.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('56d2b2f0-b7a4-448f-acba-955eb269b59c', $q$Mobile Apps$q$, $q$Native iOS and Android apps let attorneys track time, review matters, and check calendars away from the office.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('56d2b2f0-b7a4-448f-acba-955eb269b59c', $q$Purpose-built for law firm workflows, including trust accounting and IOLTA-related compliance$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('56d2b2f0-b7a4-448f-acba-955eb269b59c', $q$Tiered pricing lets firms start small and add advanced billing or accounting features as they grow$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('56d2b2f0-b7a4-448f-acba-955eb269b59c', $q$Native iOS and Android apps support time tracking and matter review away from the office$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('56d2b2f0-b7a4-448f-acba-955eb269b59c', $q$QuickBooks integration reduces duplicate data entry between billing and bookkeeping$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('56d2b2f0-b7a4-448f-acba-955eb269b59c', $q$Backing from ProfitSolv provides continuity alongside sibling products like TimeSolv$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('56d2b2f0-b7a4-448f-acba-955eb269b59c', $q$Advanced features such as matter budgets, split billing, and full legal accounting are reserved for higher-priced tiers$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('56d2b2f0-b7a4-448f-acba-955eb269b59c', $q$Per-user monthly pricing can add up for larger firms compared with flat-rate alternatives$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('56d2b2f0-b7a4-448f-acba-955eb269b59c', $q$Feature set is tailored to legal workflows, offering limited value outside law firm use cases$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('56d2b2f0-b7a4-448f-acba-955eb269b59c', $q$Some capabilities, like the enterprise CRM add-on, carry additional cost beyond the base subscription$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('56d2b2f0-b7a4-448f-acba-955eb269b59c', $q$Firms with highly specialized enterprise or multi-office requirements may need customization beyond what the platform offers out of the box$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('56d2b2f0-b7a4-448f-acba-955eb269b59c', $q$What is Rocket Matter used for?$q$, $q$Rocket Matter is legal practice management software that law firms use to manage matters, track time, bill clients, and handle trust accounting in one system.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('56d2b2f0-b7a4-448f-acba-955eb269b59c', $q$Does Rocket Matter offer a free trial?$q$, $q$Yes, Rocket Matter offers a free trial so firms can evaluate matter management, billing, and trust accounting features before subscribing to a paid plan.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('56d2b2f0-b7a4-448f-acba-955eb269b59c', $q$How is Rocket Matter priced?$q$, $q$Rocket Matter uses per-user monthly pricing across four tiers, Essentials, Pro, Premier, and Elite, with lower rates available on annual billing.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('56d2b2f0-b7a4-448f-acba-955eb269b59c', $q$Is Rocket Matter available on mobile devices?$q$, $q$Yes, Rocket Matter provides native iOS and Android apps so attorneys can track time and review matters away from their desks.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('56d2b2f0-b7a4-448f-acba-955eb269b59c', $q$Who owns Rocket Matter?$q$, $q$Rocket Matter has been owned by ProfitSolv since 2020, a group that also owns legal and accounting software companies TimeSolv and ImagineTime.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('56d2b2f0-b7a4-448f-acba-955eb269b59c', $q$Solo attorney managing billing and matters$q$, $q$A solo practitioner uses Rocket Matter to track billable time, send invoices, and keep client matters organized without maintaining separate spreadsheets or billing software.$q$, $q$Solo attorneys$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('56d2b2f0-b7a4-448f-acba-955eb269b59c', $q$Small firm handling client trust funds$q$, $q$A small firm uses matter-based trust accounts to manage retainers and client funds in line with trust accounting requirements while billing from the same platform.$q$, $q$Small law firms$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('56d2b2f0-b7a4-448f-acba-955eb269b59c', $q$Mid-sized firm coordinating multiple timekeepers$q$, $q$A firm with several attorneys and paralegals uses shared calendars, task assignment, and centralized reporting to coordinate work and monitor billing across many open matters.$q$, $q$Mid-sized law firms$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('56d2b2f0-b7a4-448f-acba-955eb269b59c', $q$Firm syncing legal billing with bookkeeping$q$, $q$A firm connects Rocket Matter to QuickBooks so billing and payment data flow into its general ledger automatically, reducing manual reconciliation work.$q$, $q$Firms using QuickBooks for accounting$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('56d2b2f0-b7a4-448f-acba-955eb269b59c', $q$Essentials$q$, $q$$59/user/month$q$, $q$Annual$q$, $q$["Matter management","Time tracking and billing","Rocket Matter Pay","25GB document storage","Limited dashboards and saved views","5 eSignatures per user/month"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('56d2b2f0-b7a4-448f-acba-955eb269b59c', $q$Pro$q$, $q$$95/user/month$q$, $q$Annual$q$, $q$["Everything in Essentials","Matter templates","Kanban-style matter management","Flat fee billing and trust accounting","Unlimited document storage","Unlimited dashboards and saved views","15 eSignatures per user/month","Optional legal CRM add-on"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('56d2b2f0-b7a4-448f-acba-955eb269b59c', $q$Premier$q$, $q$$115/user/month$q$, $q$Annual$q$, $q$["Everything in Pro","Advanced user and billing permissions","Split billing and fee allocation","Matter-based trust accounts","Custom rate management","Optional legal CRM add-on"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('56d2b2f0-b7a4-448f-acba-955eb269b59c', $q$Elite$q$, $q$$145/user/month$q$, $q$Annual$q$, $q$["Everything in Premier","Matter budgets","Full legal accounting","Auto trust transfer","Workbench dashboard access"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('56d2b2f0-b7a4-448f-acba-955eb269b59c', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Rocket Matter is a cloud-based legal practice management platform built for law firms that need to track time, bill clients, manage trust accounts, and keep matters organized in one system. Founded in 2007 and headquartered in Boca Raton, Florida, the company has spent more than a decade focused specifically on the day-to-day workflows of legal professionals rather than on general-purpose project management or accounting software.$q$, $q$Since 2020, Rocket Matter has operated as part of ProfitSolv, a group of legal and accounting software companies that also includes TimeSolv and ImagineTime. That ownership change has not altered the product's core focus: helping firms capture billable time, invoice clients accurately, and manage the financial side of running a law practice without stitching together spreadsheets, separate billing tools, and email.$q$, $q$The platform runs entirely in a web browser, with companion iOS and Android apps so attorneys can log time, review matters, or check calendars away from their desks. Pricing is structured as a per-user monthly subscription split across four tiers, with a free trial available so firms can test the software's matter management, billing, and trust accounting tools before committing to an annual contract. Rocket Matter also lists SOC 2 Type 2 and PCI certifications, along with end-to-end encryption, which matter to firms that handle sensitive client records and client trust funds.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('56d2b2f0-b7a4-448f-acba-955eb269b59c', $q$who-rocket-matter-is-for$q$, $q$Who Rocket Matter Is For$q$, 2, ARRAY[$q$Rocket Matter is aimed primarily at solo attorneys and small-to-midsize law firms that want a single system for running daily operations, from opening a new matter through sending the final invoice. Firms in practice areas such as personal injury, family law, estate planning, real estate, and general business law are common users, since the software's matter templates and workflows can be configured around those specific practice types.$q$, $q$It also suits firms that are outgrowing generic tools like spreadsheets, shared email inboxes, and standalone billing software, and want trust accounting, time tracking, and case management combined into one connected system. Because pricing scales by tier, a growing firm can start on the lower-cost Essentials plan and move up to add features like advanced billing permissions, matter budgets, or full legal accounting as headcount and case volume increase.$q$, $q$Firms that already keep their books in QuickBooks tend to find Rocket Matter appealing because of its accounting integration, which cuts down on duplicate data entry between legal billing and the general ledger. Mid-sized firms with several timekeepers who need shared calendars, task assignment, and centralized reporting across many open matters are also a strong fit for the platform, particularly once they outgrow the lowest pricing tier and need matter-based trust accounts or custom rate management.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('56d2b2f0-b7a4-448f-acba-955eb269b59c', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Very large law firms, or firms with highly specialized enterprise requirements such as conflict-checking across hundreds of attorneys or deep integration with an existing enterprise resource planning system, may find Rocket Matter's feature set oriented more toward small and mid-sized practices than toward large-firm operations with dedicated IT departments.$q$, $q$Firms outside the legal industry, such as accounting or general professional services businesses, are generally better served by one of ProfitSolv's other products or by a general-purpose practice management tool, since Rocket Matter's workflows, terminology, and compliance features are built specifically around legal trust accounting and matter-based billing rules like IOLTA compliance.$q$, $q$Solo practitioners or very small firms on a tight budget who only need basic time tracking or simple invoicing, without trust accounting or full matter management, may find the per-user monthly pricing harder to justify compared with lighter, lower-cost billing tools that skip the broader practice management feature set entirely.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('56d2b2f0-b7a4-448f-acba-955eb269b59c', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$Core capabilities include matter and case management, time and expense tracking, legal billing, and trust accounting, all built to support the IOLTA compliance requirements that govern how law firms handle client funds. Firms can track billable and non-billable time from a desktop browser or a mobile app, then turn that time into an invoice without re-entering data.$q$, $q$Higher tiers add flat-fee billing, matter-based trust accounts, custom rate management, matter budgets, split billing, fee allocation, and advanced user or billing permissions, giving larger firms more control over how revenue and trust funds are tracked across partners, associates, and practice groups.$q$, $q$Beyond billing, Rocket Matter includes calendaring, task management, contact management, customizable dashboards, saved views, electronic signatures, document sharing, a built-in legal CRM for business development, and reporting tools, along with a QuickBooks integration for firms that keep their general ledger outside the platform. Optional add-ons, such as a more advanced legal CRM tier and website hosting, let firms extend the base subscription without switching to a different product.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('56d2b2f0-b7a4-448f-acba-955eb269b59c', $q$the-rocket-matter-experience$q$, $q$The Rocket Matter Experience$q$, 2, ARRAY[$q$Day to day, Rocket Matter is designed to feel like a single dashboard a lawyer can return to throughout the day rather than a set of disconnected modules. Matters, contacts, calendar entries, tasks, and time entries are all linked, so opening a case shows the relevant documents, deadlines, and billing history in one view instead of requiring a search across separate tools.$q$, $q$The interface leans on customizable dashboards and saved views so different roles at a firm, such as an associate tracking their own time versus a billing administrator reviewing firm-wide invoices, can see the information most relevant to them without extra configuration. Mobile apps extend that same experience so time entry and matter updates are not limited to the office.$q$, $q$Because the product is delivered as a subscription with tiered plans, the overall experience also depends on which tier a firm selects: Essentials covers core matter management and billing, while Pro, Premier, and Elite progressively unlock more automation, permissions, and legal accounting depth, meaning the day-to-day feel of the software can change meaningfully depending on plan level.$q$]::text[], 4);
