INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bf5ccccf-0e75-4299-a56e-49f4447411f2', $q$Resource Scheduling$q$, $q$Drag-and-drop planner for assigning people to projects, spotting gaps and overbooking, and adjusting schedules across the whole team in one view.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bf5ccccf-0e75-4299-a56e-49f4447411f2', $q$Capacity and Utilization Reporting$q$, $q$Real-time charts show who is over- or under-utilized, helping managers rebalance workloads before deadlines slip.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bf5ccccf-0e75-4299-a56e-49f4447411f2', $q$Project Financials$q$, $q$Tracks budgets, costs, and revenue per project so leaders can see margins and profitability alongside the schedule.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bf5ccccf-0e75-4299-a56e-49f4447411f2', $q$Forecasting$q$, $q$Projects future utilization, revenue, and staffing needs based on confirmed and tentative work already in the plan.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bf5ccccf-0e75-4299-a56e-49f4447411f2', $q$Scenario Planning$q$, $q$Tentative and draft projects can be modeled against confirmed work to test different staffing scenarios before committing.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bf5ccccf-0e75-4299-a56e-49f4447411f2', $q$Timesheets$q$, $q$Team members log actual hours against planned assignments, letting managers compare planned versus actual effort.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bf5ccccf-0e75-4299-a56e-49f4447411f2', $q$Skills and Tags$q$, $q$People and roles can be tagged by skill, seniority, or discipline, making it easier to match the right person to a project.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bf5ccccf-0e75-4299-a56e-49f4447411f2', $q$Integrations and API$q$, $q$Connects to tools like Harvest, ClickUp, Asana, and accounting systems, with an open API for custom workflows.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bf5ccccf-0e75-4299-a56e-49f4447411f2', $q$Custom Fields and Dashboards$q$, $q$Advanced-tier customers can build custom fields, reports, and insight dashboards tailored to their own workflows.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bf5ccccf-0e75-4299-a56e-49f4447411f2', $q$Audit Log and SSO$q$, $q$Standard and Advanced plans add an activity audit log and SAML single sign-on for larger, security-conscious teams.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bf5ccccf-0e75-4299-a56e-49f4447411f2', $q$Free plan available for small teams with no credit card required$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bf5ccccf-0e75-4299-a56e-49f4447411f2', $q$Intuitive drag-and-drop scheduling that is easy to learn$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bf5ccccf-0e75-4299-a56e-49f4447411f2', $q$Strong project financial forecasting built directly into the schedule$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bf5ccccf-0e75-4299-a56e-49f4447411f2', $q$Scenario planning lets teams test tentative staffing before committing$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bf5ccccf-0e75-4299-a56e-49f4447411f2', $q$Integrates with existing project management and accounting tools rather than replacing them$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bf5ccccf-0e75-4299-a56e-49f4447411f2', $q$Not a task-management tool, so teams still need separate software for day-to-day task tracking$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bf5ccccf-0e75-4299-a56e-49f4447411f2', $q$Paid plans require a minimum number of resource seats, which can be costly for very small paid teams$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bf5ccccf-0e75-4299-a56e-49f4447411f2', $q$Advanced plan pricing is not published and requires contacting sales$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bf5ccccf-0e75-4299-a56e-49f4447411f2', $q$Timesheets, integrations, and API access are gated behind the Standard tier and above$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bf5ccccf-0e75-4299-a56e-49f4447411f2', $q$No native mobile apps; the product is web-based only$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('bf5ccccf-0e75-4299-a56e-49f4447411f2', $q$Does Runn have a free plan?$q$, $q$Yes, Runn offers a free plan for teams managing 5 or fewer people, with no credit card required to start.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('bf5ccccf-0e75-4299-a56e-49f4447411f2', $q$What is the difference between the Lite and Standard plans?$q$, $q$Standard includes everything in Lite plus timesheets, custom fields, integrations, API access, and an audit log.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('bf5ccccf-0e75-4299-a56e-49f4447411f2', $q$Does Runn integrate with other tools?$q$, $q$Yes, Runn connects with tools such as Harvest, ClickUp, Asana, and accounting systems, and offers an open API on Standard and Advanced plans.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('bf5ccccf-0e75-4299-a56e-49f4447411f2', $q$Is there a minimum team size to use Runn?$q$, $q$The free plan supports up to 5 people; paid plans generally require a minimum number of resource seats, so very small paid teams should check current terms on the pricing page.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('bf5ccccf-0e75-4299-a56e-49f4447411f2', $q$Does Runn replace project management software like Asana or Jira?$q$, $q$No, Runn focuses on resource scheduling, capacity planning, and financial forecasting, and is designed to work alongside task-management tools rather than replace them.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bf5ccccf-0e75-4299-a56e-49f4447411f2', $q$Agency Resource Scheduling$q$, $q$Marketing and creative agencies use Runn to schedule staff across multiple client projects and avoid overbooking key people.$q$, $q$Agency operations and resourcing managers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bf5ccccf-0e75-4299-a56e-49f4447411f2', $q$Professional Services Capacity Planning$q$, $q$Consulting and services firms plan billable utilization and staffing needs across concurrent client engagements.$q$, $q$Professional services leaders and PMOs$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bf5ccccf-0e75-4299-a56e-49f4447411f2', $q$Software and Engineering Team Allocation$q$, $q$Engineering teams allocate developers and specialists across products and sprints while tracking capacity.$q$, $q$Engineering managers and delivery leads$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bf5ccccf-0e75-4299-a56e-49f4447411f2', $q$Financial Forecasting for Project-Based Businesses$q$, $q$Finance teams forecast project revenue, margins, and staffing costs using real-time scheduling data.$q$, $q$Finance teams and business operations leaders$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('bf5ccccf-0e75-4299-a56e-49f4447411f2', $q$Free$q$, $q$$0$q$, $q$N/A$q$, $q$["Up to 5 managed people","Scheduling and capacity charts","Unlimited users and projects","No credit card required"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('bf5ccccf-0e75-4299-a56e-49f4447411f2', $q$Lite$q$, $q$$7 per person/month$q$, $q$Monthly or annual$q$, $q$["Scheduling and tentative projects","Capacity and utilization charts","Skills and tags","Project financials"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('bf5ccccf-0e75-4299-a56e-49f4447411f2', $q$Standard$q$, $q$$11 per person/month$q$, $q$Monthly or annual$q$, $q$["Everything in Lite","Timesheets","5 custom fields","Integrations and API access","30-day audit activity log"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('bf5ccccf-0e75-4299-a56e-49f4447411f2', $q$Advanced$q$, $q$Custom (contact sales)$q$, $q$Annual$q$, $q$["Everything in Standard","Unlimited custom fields and reports","Workstreams","Custom insight dashboards","SAML SSO"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bf5ccccf-0e75-4299-a56e-49f4447411f2', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Runn is a resource planning and forecasting platform built for project-based businesses that need to schedule people, track capacity, and understand project financials in one place. Rather than managing day-to-day tasks, Runn focuses on the layer above execution: who is working on what, how much of their time is committed, and what that means for revenue and margin across the whole portfolio of work.$q$, $q$The product centers on a visual, drag-and-drop schedule that shows every person and every project on a single timeline. Managers can see at a glance who is overbooked, who has spare capacity, and how upcoming work will affect utilization weeks or months ahead, which supports both short-term staffing decisions and longer-term hiring and pipeline planning conversations with leadership.$q$, $q$Founded in 2018 and headquartered in Wellington, New Zealand, Runn has grown into a tool used by agencies, consultancies, and technology teams around the world. It is typically adopted alongside existing project management and accounting software, filling the resourcing and forecasting gap those tools do not cover, and connecting scheduling data to the financial reality of running a project-based business. This positioning has helped Runn build a reputation as a focused resourcing layer rather than a broad, do-everything suite.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bf5ccccf-0e75-4299-a56e-49f4447411f2', $q$who-runn-is-for$q$, $q$Who Runn Is For$q$, 2, ARRAY[$q$Runn is best suited to project-based organizations that staff multiple concurrent projects with a shared pool of people, such as digital agencies, consulting firms, engineering studios, and other professional services businesses. These teams need to know, in real time, who is available, who is stretched thin, and how staffing choices affect delivery timelines and profitability across every active engagement. Multi-disciplinary teams that move people between client accounts on a weekly or monthly basis are a particularly strong fit.$q$, $q$It also appeals to operations and resourcing managers who are responsible for allocating people across projects and want a single source of truth for capacity, rather than piecing that view together from spreadsheets or task boards. Finance leaders and executives benefit too, since Runn ties scheduling directly to project budgets and revenue forecasts, turning a staffing decision into a visible financial one.$q$, $q$Teams that bill clients by the hour or track utilization as a core business metric tend to get the most value, because Runn was built around exactly that workflow: matching people to billable work, watching utilization trends over time, and forecasting how the pipeline of tentative and confirmed projects will affect staffing needs and revenue in the coming quarters.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bf5ccccf-0e75-4299-a56e-49f4447411f2', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Runn is not a task-management or project-execution tool, so teams looking for kanban boards, task lists, or sprint tracking will still need separate software for that layer of work. Organizations hoping for a single all-in-one platform that replaces both task management and resourcing may find Runn only covers part of that need and requires pairing with another tool.$q$, $q$Very small teams or solo freelancers may find the paid tiers less economical, since paid plans are priced per resource seat and typically carry a minimum seat requirement; the free plan covers only teams of 5 or fewer managed people, which limits how far an organization can grow before paid pricing applies and before the per-seat cost becomes a meaningful line item. Teams that only occasionally need to plan resourcing may find the ongoing per-seat cost hard to justify compared with an ad hoc spreadsheet.$q$, $q$Companies that need heavier customization, advanced security controls such as SSO, or deep custom reporting out of the box should note that these capabilities sit on the higher-priced Advanced tier, which requires contacting sales rather than self-serve signup, so budget-constrained teams evaluating those specific features should plan for that sales conversation in advance.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bf5ccccf-0e75-4299-a56e-49f4447411f2', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At the core of Runn is its scheduling grid, where every person, project, and assignment lives on a shared timeline. Capacity and utilization charts sit alongside the schedule so managers can immediately see the effect of adding or moving an assignment, including whether it pushes someone into overbooked territory or leaves a specialist underused for the week.$q$, $q$Project financials are built into the same view: budgets, costs, and revenue are tracked per project, and forecasting tools project how confirmed and tentative work will affect future utilization and revenue. Scenario planning lets teams model draft or unconfirmed projects against real capacity before committing resources, so a sales pipeline can be tested against the team's actual availability.$q$, $q$Beyond scheduling and forecasting, Runn supports timesheets for comparing planned versus actual hours, skills and tags for matching people to the right work, and integrations with tools such as Harvest, ClickUp, Asana, and accounting platforms through its API. Higher tiers add unlimited custom fields, custom insight dashboards, an audit activity log, and SAML single sign-on for larger organizations. This combination lets larger organizations enforce their own data structures and reporting standards on top of Runn's core scheduling engine.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bf5ccccf-0e75-4299-a56e-49f4447411f2', $q$the-runn-experience$q$, $q$The Runn Experience$q$, 2, ARRAY[$q$Day to day, using Runn feels closer to working with a live staffing spreadsheet than a traditional project management app. The interface is visual and color-coded, with people and projects arranged as rows so patterns of over- and under-utilization are easy to spot without digging through separate reports or exporting data elsewhere.$q$, $q$New users generally find the core scheduling workflow quick to pick up, since most actions are a matter of dragging an assignment onto the timeline and adjusting its length or hours. The financial and forecasting views build on that same underlying data, so once a schedule is populated, budget and revenue projections update automatically without extra manual data entry. Support resources and a searchable help center are also available for teams getting started with more advanced configuration.$q$, $q$Because Runn is delivered entirely as a web application, it works the same way across devices with a modern browser, though there is no dedicated native mobile app for iOS or Android. Teams typically run it in parallel with their existing project management, accounting, and HR tools, feeding data in and out through integrations or the open API rather than replacing that stack outright.$q$]::text[], 4);
