INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('82e23514-860e-4179-aa6e-cc95f88d7372', $q$Frequent plan and model changes can make long-term cost planning harder$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('82e23514-860e-4179-aa6e-cc95f88d7372', $q$What is Runway used for?$q$, $q$Runway is used to generate and edit AI video, image, and audio content, including text-to-video and image-to-video clips, for film, marketing, and general content creation.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('82e23514-860e-4179-aa6e-cc95f88d7372', $q$Does Runway have a free plan?$q$, $q$Yes, Runway offers a free plan with a one-time credit allowance so new users can try its generation tools before subscribing to a paid plan.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('82e23514-860e-4179-aa6e-cc95f88d7372', $q$How does Runway's credit system work?$q$, $q$Each generation consumes credits based on output length and the model used, and paid plans include a monthly credit allowance that scales with the plan tier.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('82e23514-860e-4179-aa6e-cc95f88d7372', $q$Can I use Runway through an API?$q$, $q$Yes, Runway provides an API that lets developers call its generative video and image models programmatically from their own applications.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('82e23514-860e-4179-aa6e-cc95f88d7372', $q$Is Runway suitable for professional film production?$q$, $q$Runway is used by professionals for previsualization, concept work, and stylized shots, but frame-accurate control needed for some broadcast or continuity-heavy work may still require traditional production methods.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('82e23514-860e-4179-aa6e-cc95f88d7372', $q$AI Short Film and Concept Production$q$, $q$Creators use Runway's text-to-video and image-to-video tools to previsualize scenes or produce full experimental short films without a traditional shoot.$q$, $q$Independent filmmakers and content creators$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('82e23514-860e-4179-aa6e-cc95f88d7372', $q$Marketing and Social Video Content$q$, $q$Marketing teams generate short product, promotional, or social clips quickly to keep pace with campaign and posting schedules.$q$, $q$Marketing and social media teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('82e23514-860e-4179-aa6e-cc95f88d7372', $q$Agency Concept Prototyping$q$, $q$Agencies use Runway to mock up visual concepts and pitch ideas to clients before committing to full production budgets.$q$, $q$Creative and advertising agencies$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('82e23514-860e-4179-aa6e-cc95f88d7372', $q$Programmatic Video Generation$q$, $q$Developers integrate Runway's API into their own apps or pipelines to generate video and image assets at scale.$q$, $q$Developers and product teams building custom workflows$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('82e23514-860e-4179-aa6e-cc95f88d7372', $q$Free$q$, $q$$0$q$, $q$Free$q$, $q$["125 one-time credits","Access to core video, image, and audio generation tools","3 video editor projects","5GB storage"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('82e23514-860e-4179-aa6e-cc95f88d7372', $q$Standard$q$, $q$$12/month (billed annually), $15/month billed monthly$q$, $q$Monthly or annual$q$, $q$["625 credits per month","All AI image and video models","4K upscaling","No watermarks"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('82e23514-860e-4179-aa6e-cc95f88d7372', $q$Pro$q$, $q$$28/month (billed annually), $35/month billed monthly$q$, $q$Monthly or annual$q$, $q$["2,250 credits per month","Custom voice creation for lip sync and text-to-speech","500GB storage","Access to the best available models"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('82e23514-860e-4179-aa6e-cc95f88d7372', $q$Max$q$, $q$$76/month (billed annually), $95/month billed monthly$q$, $q$Monthly or annual$q$, $q$["9,500 credits per month","One-month credit rollover","First access to newest models","Highest generation volume"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('82e23514-860e-4179-aa6e-cc95f88d7372', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Runway, also known as RunwayML, is a New York based AI research and product company, founded in 2018, that builds generative tools for creating and editing video, image, and audio content. Its core product is a browser based suite that pairs proprietary generative video models, currently branded Gen-4.5, with an editor for turning text prompts, still images, or existing footage into new video clips, giving individual creators access to production techniques that once required much larger crews and budgets.$q$, $q$The company was started by Cristobal Valenzuela, Anastasis Germanidis, and Alejandro Matamala after meeting at New York University's Tisch School of the Arts ITP program, and it has since grown into one of the more recognized names in AI video generation, competing alongside tools from much larger labs while remaining an independently operated, venture backed company headquartered in New York City with a growing team of researchers, engineers, and product staff.$q$, $q$Beyond text-to-video and image-to-video generation, Runway packages a set of adjacent tools, motion tracking, green screen removal, inpainting, camera control, lip sync, and voice generation, into a single workspace, positioning itself less as a single model and more as an end to end creative production environment for AI generated media, spanning early concept work through final export of a finished clip.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('82e23514-860e-4179-aa6e-cc95f88d7372', $q$who-runway-is-for$q$, $q$Who Runway Is For$q$, 2, ARRAY[$q$Runway is aimed at filmmakers, video editors, and motion designers who want to generate b-roll, concept footage, or stylized shots without a full production crew, camera equipment, or location shoot, along with marketing and social teams that need a steady output of short video ads, product clips, or promotional content on a compressed timeline and limited budget.$q$, $q$Independent creators and small studios exploring AI filmmaking use Runway to storyboard, previsualize, or fully produce short experimental pieces, while agencies use it to prototype concepts for clients quickly before committing to traditional production budgets and schedules, letting a small team present several visual directions in the time a single traditional shoot would take.$q$, $q$Product and brand teams that need repeatable, on-brand visual content, along with educators and researchers experimenting with generative media, also find Runway's mix of video, image, and audio tools useful for rapid iteration inside a single workspace rather than stitching together several separate applications, since a project can move from a text prompt to a shareable clip within one browser tab.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('82e23514-860e-4179-aa6e-cc95f88d7372', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Teams that need frame accurate, fully controllable footage, such as broadcast production requiring exact continuity or precise, repeatable actor performances, will find generative video's inherent unpredictability a poor fit, since outputs can drift from a prompt in ways traditional filming or manual animation would not, and reshoots are prompt based rather than fully directable in the way a camera operator can be.$q$, $q$High volume users planning to generate long-form video at scale should evaluate the credit economics carefully, since every generated second consumes credits, and costs can climb quickly for teams producing many long clips a month, making Runway less cost efficient than traditional stock footage or in-house filming for large scale, repetitive production needs.$q$, $q$Organizations with strict compliance or data residency requirements, or those unwilling to work through occasional visual artifacts and inconsistencies common to current generative video models, may prefer to wait for more mature tooling or pair Runway with heavier human review before relying on it for mission critical or heavily regulated content, particularly in advertising, healthcare, legal, or financial contexts where accuracy expectations are especially high.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('82e23514-860e-4179-aa6e-cc95f88d7372', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At the center of Runway is its generative video model line, currently Gen-4.5, which supports text-to-video, image-to-video, and video-to-video generation, alongside Act-Two for transferring an actor's performance onto a generated character and Frames for high fidelity AI image generation with consistent style controls across a project.$q$, $q$The editing toolkit includes green screen and background removal without a physical green screen, a motion brush and camera controls for directing movement within a generated shot, inpainting and object removal for cleaning up footage, and custom voice and lip sync tools for adding narration or dialogue to generated characters, all accessible from the same project window.$q$, $q$Runway also ships a timeline based video editor for assembling generated and uploaded clips, a shared asset library and workspace for team collaboration, and an API for developers who want to call Runway's models programmatically from their own applications rather than the web interface, which supports building custom tools, integrations, and automated content pipelines around the same underlying models used in the consumer product.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('82e23514-860e-4179-aa6e-cc95f88d7372', $q$the-runway-experience$q$, $q$The Runway Experience$q$, 2, ARRAY[$q$Runway's interface is entirely browser based, organized around a project workspace where users prompt for generations, review results, and drag clips into a lightweight timeline editor, so no local software installation is required, and most actions, from typing a prompt to exporting a clip, happen within a few clicks on a fairly approachable, uncluttered layout.$q$, $q$Every generation draws from a monthly credit allowance that scales with the paid plan, and the free tier offers a limited one-time credit grant, which lets new users test the core generation quality, review turnaround time, and general workflow before deciding whether the output justifies moving to a paid subscription.$q$, $q$The overall experience rewards iteration and experimentation: generations are quick, prompts often need a few attempts to get right, and the company pushes new models and features often, so the platform can feel like a moving target, though it has generally kept the same core workspace and pricing structure since launch, which keeps the learning curve manageable for returning users familiar with earlier model generations.$q$]::text[], 4);
