INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ae913412-1cd7-414a-b291-f3e2c6aabc3b', $q$Use-Case Templates$q$, $q$Dozens of purpose-built templates for blog ideas, product descriptions, ads, emails, and social captions.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ae913412-1cd7-414a-b291-f3e2c6aabc3b', $q$Tone Matching$q$, $q$Analyzes a sample of a user's writing and generates new text that leans toward the same tone and style.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ae913412-1cd7-414a-b291-f3e2c6aabc3b', $q$Plagiarism Checker$q$, $q$Built-in originality check against existing web content, with a monthly check allowance that scales by plan.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ae913412-1cd7-414a-b291-f3e2c6aabc3b', $q$Multi-Language Writing$q$, $q$Generate content in 30+ languages, with the widest language coverage available on the Premium plan.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ae913412-1cd7-414a-b291-f3e2c6aabc3b', $q$Chrome Extension$q$, $q$A browser extension that brings Rytr's generation tools into other web apps and text fields.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ae913412-1cd7-414a-b291-f3e2c6aabc3b', $q$Text Editing Tools$q$, $q$Rephrase, expand, and shorten generated or pasted text to fit a target length or style.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ae913412-1cd7-414a-b291-f3e2c6aabc3b', $q$API Access$q$, $q$Programmatic access to Rytr's generation engine for teams building it into their own apps, available on Premium.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ae913412-1cd7-414a-b291-f3e2c6aabc3b', $q$Custom Use Cases$q$, $q$Premium-tier ability to define tailored templates beyond the default use-case library.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ae913412-1cd7-414a-b291-f3e2c6aabc3b', $q$Custom Tone Profiles$q$, $q$Save multiple distinct tone profiles, useful for freelancers writing for several clients or brands.$q$, 8);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ae913412-1cd7-414a-b291-f3e2c6aabc3b', $q$Free plan is genuinely usable for testing the product before paying$q$, 0);
